<?php
namespace App\Domain\Equipment\Data;
final class CharacterEquipmentStats{private $base;private $refinement;private $total;private $sources;public function __construct(ItemStatBonuses $total,array $sources,ItemStatBonuses $base=null,ItemStatBonuses $refinement=null){$this->total=$total;$this->base=$base?:$total;$this->refinement=$refinement?:new ItemStatBonuses();$this->sources=array_values($sources);}public function baseBonuses(){return$this->base;}public function refinementBonuses(){return$this->refinement;}public function totalBonuses(){return$this->total;}public function bonuses(){return$this->totalBonuses();}public function sources(){return array_map(function($source){foreach(['base_bonuses','refinement_bonuses','total_bonuses','bonuses'] as $key)if(isset($source[$key]))$source[$key]=array_merge([],$source[$key]);return array_merge([],$source);},$this->sources);}}
